// Build HTML node - parses AI JSON output and builds a fixed-layout A4 resume HTML
const raw = $input.first().json.output || $input.first().json.text || '';

let cleaned = String(raw).trim();
cleaned = cleaned.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();

let data;
try {
  data = JSON.parse(cleaned);
} catch (e) {
  throw new Error('AI did not return valid JSON. Raw output: ' + cleaned.slice(0, 500));
}

const esc = (s) => String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const list = (arr) => Array.isArray(arr) ? arr : [];

const competencies = list(data.competencies).map(c => `<span class="chip">${esc(c)}</span>`).join('');
const skills = list(data.skills).map(s => `<li>${esc(s)}</li>`).join('');
const tools = list(data.tools).map(t => `<li>${esc(t)}</li>`).join('');
const strengths = list(data.strengths).map(s => `<li>${esc(s)}</li>`).join('');
const achievements = list(data.achievements).map(a => `<li>${esc(a)}</li>`).join('');

const education = list(data.education).map(ed => `
  <div class="edu-item">
    <div class="edu-degree">${esc(ed.degree)}</div>
    <div class="edu-meta">${esc(ed.institution)} ${ed.year ? '&middot; ' + esc(ed.year) : ''}</div>
  </div>`).join('');

const experience = list(data.experience).map(job => `
  <div class="job">
    <div class="job-header">
      <span class="job-title">${esc(job.title)}</span>
      <span class="job-dates">${esc(job.start)} - ${esc(job.end)}</span>
    </div>
    <div class="job-company">${esc(job.company)}</div>
    <ul class="job-bullets">
      ${list(job.bullets).map(b => `<li>${esc(b)}</li>`).join('')}
    </ul>
  </div>`).join('');

const html = `<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<style>
  @page { size: A4; margin: 0; }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: 'Helvetica Neue', Arial, sans-serif; color: #222; width: 210mm; min-height: 296mm; display: flex; }
  .sidebar { width: 72mm; background: #1a2e4a; color: #fff; padding: 12mm 8mm; display: flex; flex-direction: column; min-height: 296mm; }
  .main { flex: 1; padding: 12mm 10mm; display: flex; flex-direction: column; min-height: 296mm; }
  .name { font-size: 20pt; font-weight: 700; letter-spacing: 0.5px; line-height: 1.2; }
  .job-title-header { font-size: 11pt; color: #2980b9; font-weight: 600; margin-top: 3mm; margin-bottom: 8mm; }
  .sidebar h3, .main h3 { font-size: 10pt; text-transform: uppercase; letter-spacing: 1px; margin-bottom: 3mm; }
  .sidebar h3 { color: #2980b9; border-bottom: 1px solid rgba(255,255,255,0.25); padding-bottom: 1.5mm; }
  .main h3 { color: #1a2e4a; border-bottom: 2px solid #2980b9; padding-bottom: 1.5mm; }
  .sidebar-section { margin-bottom: 7mm; font-size: 9pt; }
  .sidebar-section ul { list-style: none; }
  .sidebar-section li { margin-bottom: 1.8mm; line-height: 1.4; }
  .contact-item { margin-bottom: 1.8mm; font-size: 8.5pt; word-break: break-word; }
  .main-section { margin-bottom: 6mm; }
  .summary { font-size: 9.5pt; line-height: 1.55; text-align: justify; }
  .chip { display: inline-block; background: #eaf1f8; color: #1a2e4a; font-size: 8pt; padding: 1mm 2.5mm; margin: 0 1.5mm 1.5mm 0; border-radius: 3mm; }
  .job { margin-bottom: 5mm; }
  .job-header { display: flex; justify-content: space-between; align-items: baseline; }
  .job-title { font-size: 10.5pt; font-weight: 700; color: #1a2e4a; }
  .job-dates { font-size: 8.5pt; color: #555; }
  .job-company { font-size: 9.5pt; font-weight: 600; color: #2980b9; margin-bottom: 1.5mm; }
  .job-bullets { padding-left: 4mm; font-size: 9pt; line-height: 1.5; }
  .job-bullets li { margin-bottom: 1mm; }
  .edu-item { margin-bottom: 3mm; font-size: 9pt; }
  .edu-degree { font-weight: 600; }
  .edu-meta { color: #555; font-size: 8.5pt; }
  .achv-list { padding-left: 4mm; font-size: 9pt; line-height: 1.5; }
  .fill { flex-grow: 1; }
</style>
</head>
<body>
  <div class="sidebar">
    <div class="sidebar-section">
      <h3>Contact</h3>
      <div class="contact-item">${esc(data.phone)}</div>
      <div class="contact-item">${esc(data.email)}</div>
      <div class="contact-item">${esc(data.location)}</div>
    </div>
    <div class="sidebar-section">
      <h3>Core Competencies</h3>
      <div>${competencies}</div>
    </div>
    <div class="sidebar-section">
      <h3>Skills</h3>
      <ul>${skills}</ul>
    </div>
    <div class="sidebar-section">
      <h3>Tools</h3>
      <ul>${tools}</ul>
    </div>
    <div class="sidebar-section">
      <h3>Languages</h3>
      <div class="contact-item">${esc(data.languages)}</div>
    </div>
    <div class="sidebar-section">
      <h3>Strengths</h3>
      <ul>${strengths}</ul>
    </div>
    <div class="fill"></div>
  </div>
  <div class="main">
    <div class="name">${esc(data.name)}</div>
    <div class="job-title-header">${esc(data.jobTitle)}</div>
    <div class="main-section">
      <h3>Summary</h3>
      <p class="summary">${esc(data.summary)}</p>
    </div>
    <div class="main-section">
      <h3>Experience</h3>
      ${experience}
    </div>
    <div class="main-section">
      <h3>Education</h3>
      ${education}
    </div>
    <div class="main-section">
      <h3>Key Achievements</h3>
      <ul class="achv-list">${achievements}</ul>
    </div>
    <div class="fill"></div>
  </div>
</body>
</html>`;

return [{ json: { html } }];
